      eligibleIds[resourceServices[i].resource_id] = true;
    }
  }
  var candidates = [];
  for (var j = 0; j < allResources.length; j++) {
    var r = allResources[j];
    if (r.active === false) continue;
    if (!eligibleIds[r.id]) continue;
    if (requestedId && r.id !== requestedId) continue;
    candidates.push(r);
  }
  candidates.sort(function(a, b) { return (a.sort_order || 0) - (b.sort_order || 0); });
  var first = '';
