}

function handler({ request, steps }) {
  var settings = (steps.settings && steps.settings[0]) || {};
  var service = steps.service || {};
  var allResources = steps.allResources || [];
  var resourceServices = steps.resourceServices || [];
  var workingHoursAll = steps.workingHours || [];
  var timeOffAll = steps.timeOff || [];
  var bookingsAll = steps.bookings || [];
  var requestedId = (request && request.query && request.query.resource_id) || null;

  // Filter eligible resources for the chosen service.
  var eligibleIds = {};
  for (var rsi = 0; rsi < resourceServices.length; rsi++) {
    if (resourceServices[rsi].service_id === service.id) {
      eligibleIds[resourceServices[rsi].resource_id] = true;
    }
  }
  var eligible = [];
  for (var ri = 0; ri < allResources.length; ri++) {
    var r = allResources[ri];
    if (r.active === false) continue;
    if (!eligibleIds[r.id]) continue;
    if (requestedId && r.id !== requestedId) continue;
    eligible.push(r);
  }
  eligible.sort(function(a, b) { return (a.sort_order || 0) - (b.sort_order || 0); });

  var fromMs = new Date(request.query.from).getTime();
  var toMs = new Date(request.query.to).getTime();
  var nowMs = Date.now();
  var minLead = (settings.min_lead_time_minutes || 0) * 60 * 1000;
  var maxAdv = (settings.max_advance_days || 60) * 24 * 60 * 60 * 1000;
  var earliestMs = nowMs + minLead;
  var latestMs = nowMs + maxAdv;
  var granMs = (settings.slot_granularity_minutes || 30) * 60 * 1000;
  var durationMs = (service.duration_minutes || 30) * 60 * 1000;
  var siteTz = settings.timezone || 'UTC';

  function tzMin(ms, useTz) {
    var parts = new Intl.DateTimeFormat('en-US', { timeZone: useTz, weekday: 'short', hour: '2-digit', minute: '2-digit', hour12: false }).formatToParts(new Date(ms));
    var weekdayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
    var dow = 0, h = 0, m = 0;
    for (var i = 0; i < parts.length; i++) {
      if (parts[i].type === 'weekday') dow = weekdayMap[parts[i].value] || 0;
      else if (parts[i].type === 'hour') h = parseInt(parts[i].value, 10) % 24;
      else if (parts[i].type === 'minute') m = parseInt(parts[i].value, 10);
    }
    return { dow: dow, mins: h * 60 + m };
  }
  function parseHM(hm) {
    var p = (hm || '00:00').split(':');
    return parseInt(p[0], 10) * 60 + parseInt(p[1], 10);
  }
  function overlaps(aStart, aEnd, bStart, bEnd) { return bStart < aEnd && bEnd > aStart; }

  var googleStep = steps.googleFreeBusy;
  var googleSkipped = !!(googleStep && googleStep.skipped);
  var googleByCal = (googleStep && !googleStep.skipped && googleStep.calendars) || {};

  // Dedupe by start ISO. First eligible (by sort_order) wins.
  var slotMap = {};

  for (var er = 0; er < eligible.length; er++) {
    var resource = eligible[er];
    var tz = resource.timezone || siteTz;

    var workingHours = [];
    for (var w = 0; w < workingHoursAll.length; w++) {
      var wh = workingHoursAll[w];
      if (!wh.resource_id || wh.resource_id === resource.id) workingHours.push(wh);
    }

    var timeOff = [];
    for (var t = 0; t < timeOffAll.length; t++) {
      var trow = timeOffAll[t];
      if (!trow.resource_id || trow.resource_id === resource.id) {
        var trs = new Date(trow.starts_at).getTime();
        var tre = new Date(trow.ends_at).getTime();
        if (trs < toMs && tre > fromMs) timeOff.push({ s: trs, e: tre });
      }
    }

    var bookings = [];
    for (var b = 0; b < bookingsAll.length; b++) {
      var br = bookingsAll[b];
      if (br.resource_id !== resource.id) continue;
      var bs = new Date(br.starts_at).getTime();
      var be = new Date(br.ends_at).getTime();
      if (bs < toMs && be > fromMs) bookings.push({ s: bs, e: be });
    }

    var googleBusy = [];
    if (resource.google_calendar_id && googleByCal[resource.google_calendar_id]) {
      googleBusy = googleByCal[resource.google_calendar_id].busy || [];
    }

    function withinWorkingHours(startMs, endMs) {
      var s = tzMin(startMs, tz);
      var e = tzMin(endMs, tz);
      if (s.dow !== e.dow) return false;
      for (var i = 0; i < workingHours.length; i++) {
        var rr = workingHours[i];
        if (rr.day_of_week !== s.dow) continue;
        var rs = parseHM(rr.start_time);
        var re = parseHM(rr.end_time);
        if (s.mins >= rs && e.mins <= re) return true;
      }
      return false;
    }

    var cursor = Math.ceil(fromMs / granMs) * granMs;
    while (cursor + durationMs <= toMs) {
      var slotStart = cursor;
      var slotEnd = cursor + durationMs;
      cursor += granMs;
      if (slotStart < earliestMs) continue;
      if (slotStart > latestMs) continue;
      if (!withinWorkingHours(slotStart, slotEnd)) continue;
      var blocked = false;
      for (var ti = 0; ti < timeOff.length; ti++) {
        if (overlaps(slotStart, slotEnd, timeOff[ti].s, timeOff[ti].e)) { blocked = true; break; }
      }
      if (blocked) continue;
      for (var bi = 0; bi < bookings.length; bi++) {
        if (overlaps(slotStart, slotEnd, bookings[bi].s, bookings[bi].e)) { blocked = true; break; }
      }
      if (blocked) continue;
      for (var gi = 0; gi < googleBusy.length; gi++) {
        if (overlaps(slotStart, slotEnd, new Date(googleBusy[gi].start).getTime(), new Date(googleBusy[gi].end).getTime())) { blocked = true; break; }
      }
      if (blocked) continue;
      var key = String(slotStart);
      if (!slotMap[key]) {
        slotMap[key] = {
          start: new Date(slotStart).toISOString(),
          end: new Date(slotEnd).toISOString(),
          resource_id: resource.id
        };
      }
    }
  }

  var slots = [];
  for (var k in slotMap) {
    if (Object.prototype.hasOwnProperty.call(slotMap, k)) slots.push(slotMap[k]);
  }
  slots.sort(function(a, b) {
    if (a.start < b.start) return -1;
    if (a.start > b.start) return 1;
    return 0;
  });
  return { slots: slots, googleSkipped: googleSkipped };
}

function handler({ steps, user }) {
  var parse = steps.parse || {};
  var startMs = new Date(parse.starts_at).getTime();
  var endMs = new Date(parse.ends_at).getTime();
  var requestedId = parse.resource_id || null;
  var allResources = steps.allResources || [];
  var resourceServices = steps.resourceServices || [];
  var allBookings = steps.allBookings || [];

  // Eligible resources for this service.
  var eligibleIds = {};
  for (var i = 0; i < resourceServices.length; i++) {
    if (resourceServices[i].service_id === parse.service_id) {
      eligibleIds[resourceServices[i].resource_id] = true;
    }
  }
  var candidates = [];
  for (var j = 0; j < allResources.length; j++) {
    var r = allResources[j];
    if (r.active === false) continue;
    if (!eligibleIds[r.id]) continue;
    if (requestedId && r.id !== requestedId) continue;
    candidates.push(r);
  }
  candidates.sort(function(a, b) { return (a.sort_order || 0) - (b.sort_order || 0); });

  // First candidate with no conflict at the requested slot wins.
  var assigned = null;
  for (var c = 0; c < candidates.length; c++) {
    var cand = candidates[c];
    var conflict = false;
    for (var bi = 0; bi < allBookings.length; bi++) {
      var bk = allBookings[bi];
      if (bk.resource_id !== cand.id) continue;
      var bs = new Date(bk.starts_at).getTime();
      var be = new Date(bk.ends_at).getTime();
      if (bs < endMs && be > startMs) { conflict = true; break; }
    }
    if (!conflict) { assigned = cand; break; }
  }

  // RFC4122 v4 token.
  function r16() { return Math.floor(Math.random() * 16).toString(16); }
  var token = '';
  for (var t = 0; t < 32; t++) {
    if (t === 8 || t === 12 || t === 16 || t === 20) token += '-';
    if (t === 12) token += '4';
    else if (t === 16) token += ((Math.random() * 4) | 8).toString(16);
    else token += r16();
  }

  var canCreate = !!assigned;
  // Capture user.id when authenticated; anon booking stores empty string
  // (which the data_create writes as null since the field is optional).
  var userId = (user && user.id) ? user.id : '';
  return {
    assignedResourceId: assigned ? assigned.id : '',
    canCreate: canCreate,
    conflict: !canCreate,
    canCreateWithCalendar: canCreate && !!(assigned && assigned.google_calendar_id),
    token: token,
    userId: userId
  };
}

function handler({ steps }) {
  var booking = (steps.lookup && steps.lookup[0]) || null;
  if (!booking) return { notFound: true, doCancel: false, doReschedule: false, conflict: false, success: false, hasGoogleEvent: false };
  var hasGoogleEvent = !!booking.google_event_id;
  var calendarId = (steps.resourceLookup && steps.resourceLookup.google_calendar_id) || '';
  var action = steps.parse.action;
  if (action === 'cancel') {
    return { notFound: false, doCancel: true, doReschedule: false, conflict: false, success: true, bookingId: booking.id, googleEventId: booking.google_event_id || '', calendarId: calendarId, hasGoogleEvent: hasGoogleEvent && !!calendarId };
  }
  if (action === 'reschedule') {
    var newStart = steps.parse.new_starts_at;
    var newEnd = steps.parse.new_ends_at;
    if (!newStart || !newEnd) return { notFound: false, doCancel: false, doReschedule: false, conflict: true, success: false, conflictReason: 'missing_times', hasGoogleEvent: false };
    var nsMs = new Date(newStart).getTime();
    var neMs = new Date(newEnd).getTime();
    var others = steps.existingForResource || [];
    var hasConflict = false;
    for (var i = 0; i < others.length; i++) {
      if (others[i].id === booking.id) continue;
      var bs = new Date(others[i].starts_at).getTime();
      var be = new Date(others[i].ends_at).getTime();
      if (bs < neMs && be > nsMs) { hasConflict = true; break; }
    }
    if (hasConflict) return { notFound: false, doCancel: false, doReschedule: false, conflict: true, success: false, conflictReason: 'slot_taken', hasGoogleEvent: false };
    return { notFound: false, doCancel: false, doReschedule: true, conflict: false, success: true, bookingId: booking.id, googleEventId: booking.google_event_id || '', calendarId: calendarId, hasGoogleEvent: hasGoogleEvent && !!calendarId };
  }
  return { notFound: false, doCancel: false, doReschedule: false, conflict: true, success: false, conflictReason: 'invalid_action', hasGoogleEvent: false };
}

