function handler({ steps, user }) {
  var bookings = steps.allBookings || [];
  var services = steps.allServices || [];
  var resources = steps.allResources || [];
  var userId = (user && user.id) ? user.id : '';

  var serviceMap = {};
  for (var si = 0; si < services.length; si++) {
    serviceMap[services[si].id] = services[si];
  }
  var resourceMap = {};
  for (var ri = 0; ri < resources.length; ri++) {
    resourceMap[resources[ri].id] = resources[ri];
  }

  var out = [];
  for (var i = 0; i < bookings.length; i++) {
    var b = bookings[i];
    if (b.user_id !== userId) continue;
    var svc = serviceMap[b.service_id] || {};
    var res = resourceMap[b.resource_id] || {};
    out.push({
      id: b.id,
      service_id: b.service_id,
      service_name: svc.name || '',
      resource_id: b.resource_id,
      resource_name: res.name || '',
      starts_at: b.starts_at,
      ends_at: b.ends_at,
      status: b.status,
      notes: b.notes || null,
      reschedule_token: b.reschedule_token || null,
      manage_url: b.reschedule_token ? ('/manage?token=' + b.reschedule_token) : null,
      google_event_id: b.google_event_id || null,
      created_at: b.createdAt || null
    });
  }
  out.sort(function(a, b) {
    if (a.starts_at < b.starts_at) return -1;
    if (a.starts_at > b.starts_at) return 1;
    return 0;
  });
  return { bookings: out, count: out.length };
}
